int main() {
 int listenfd, connfd;
 struct sockaddr_in servaddr;
 pid_t pid;

 // Create socket
 listenfd = socket(AF_INET, SOCK_STREAM, 0);

 // Set SO_REUSEADDR
 int opt = 1;
 setsockopt(listenfd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

 // Bind to port 8000
 bzero(&servaddr, sizeof(servaddr));
 servaddr.sin_family = AF_INET;
 servaddr.sin_addr.s_addr = htonl(INADDR_ANY);
 servaddr.sin_port = htons(8000);
 bind(listenfd, (struct sockaddr*)&servaddr, sizeof(servaddr));

 // Listen with backlog of 5
 listen(listenfd, 5);

 // Setup SIGCHLD handler for zombie prevention
 signal(SIGCHLD, sigchld_handler);

 for (;;) {
 connfd = accept(listenfd, (struct sockaddr*)NULL, NULL);

 pid = fork();
 if (pid == 0) { // Child process
 close(listenfd);
 handle_client(connfd); // Echo back data
 close(connfd);
 exit(0);
 }
 // Parent process
 close(connfd); // Close copied descriptor
 }
}

void sigchld_handler(int sig) {
 while (waitpid(-1, NULL, WNOHANG) > 0);
}

int main() {
 int sockfd;
 struct sockaddr_in servaddr;
 char recvline[MAXLINE + 1];

 // Create socket
 sockfd = socket(AF_INET, SOCK_STREAM, 0);

 // Setup server address
 bzero(&servaddr, sizeof(servaddr));
 servaddr.sin_family = AF_INET;
 servaddr.sin_port = htons(8000);

 // Convert IP address
 inet_pton(AF_INET, "127.0.0.1", &servaddr.sin_addr);

 // Connect to server (triggers 3-way handshake)
 connect(sockfd, (struct sockaddr*)&servaddr, sizeof(servaddr));

 // Read and display server response
 while (read(sockfd, recvline, MAXLINE) > 0) {
 fputs(recvline, stdout);
 }

 close(sockfd);
 exit(0);
}

// UDP Server
int main() {
 int sockfd;
 struct sockaddr_in servaddr, cliaddr;
 char mesg[MAXLINE];
 socklen_t len;

 sockfd = socket(AF_INET, SOCK_DGRAM, 0);

 bzero(&servaddr, sizeof(servaddr));
 servaddr.sin_family = AF_INET;
 servaddr.sin_addr.s_addr = htonl(INADDR_ANY);
 servaddr.sin_port = htons(9000);
 bind(sockfd, (struct sockaddr*)&servaddr, sizeof(servaddr));

 for (;;) {
 len = sizeof(cliaddr);
 // Receive from any client
 recvfrom(sockfd, mesg, MAXLINE, 0, (struct sockaddr*)&cliaddr, &len);

 // Echo back to same client
 sendto(sockfd, mesg, strlen(mesg), 0, (struct sockaddr*)&cliaddr, len);
 }
}

// UDP Client
int main() {
 int sockfd;
 struct sockaddr_in servaddr;

 sockfd = socket(AF_INET, SOCK_DGRAM, 0);

 bzero(&servaddr, sizeof(servaddr));
 servaddr.sin_family = AF_INET;
 servaddr.sin_port = htons(9000);
 inet_pton(AF_INET, "127.0.0.1", &servaddr.sin_addr);

 // No connect() needed - use sendto directly
 sendto(sockfd, "Hello\n", 6, 0, (struct sockaddr*)&servaddr, sizeof(servaddr));

 // Or use connect() for simplified send/recv
 connect(sockfd, (struct sockaddr*)&servaddr, sizeof(servaddr));
 write(sockfd, "Hello\n", 6);
 read(sockfd, mesg, MAXLINE);
}
